export function transformersStrictParityLineText(file: string, line: number): string | undefined {
  return transformersStrictParitySourceLines.find((entry) => entry.file === file && entry.line === line)?.text;
}

export function transformersStrictParityFiles(): readonly string[] {
  return [...new Set(transformersStrictParitySourceLines.map((entry) => entry.file))].sort();
}
